insert into practice_context_blocks (id, exercise_id, label, image_url, text_content, block_type) values
  ('4fa4beb3-2076-4f28-a0b0-1cb085ebe76f', 'cfa09c3b-6226-4b04-bd3d-c31f84d1ae7b', $$figuur 1 — basisstructuren PC-DD, PC-DF en PCB (substitutieregel)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-dioxines-en-pcbs-context1.png$$,
   $$figuur 1: basisstructuren van PC-DD (dibenzo-p-dioxine, twee zuurstofbruggen tussen de ringen, genummerde posities 1,2,3,4 en 6,7,8,9), PC-DF (dibenzofuraan, één zuurstofbrug, posities 1,2,3,4 en 6,7,8,9) en PCB (bifenyl, twee via een enkele C–C-binding verbonden benzeenringen, posities 2,3,4,5,6 en 2',3',4',5',6'). In elke weergegeven structuur kunnen een of meer waterstofatomen zijn vervangen door chlooratomen. In de afkortingen wordt daarom PC (polychloor) gebruikt.$$, 'inline'),
  ('3e2e9734-48e3-478a-8196-25ab74fc7747', 'cfa09c3b-6226-4b04-bd3d-c31f84d1ae7b', $$figuur 2 — structuurformules PCB-126 en PCB-54 (Seveso-inleiding)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-dioxines-en-pcbs-context2.png$$,
   $$In 1976 kwam in Seveso in Italië door een fout in de productie van 2,4,5-trichloorfenol een grote hoeveelheid 2,3,7,8-tetrachloor-DD vrij. Deze stof is de giftigste dioxine. Men heeft ontdekt dat de toxische werking hiervan mede wordt veroorzaakt door de platte vorm van de moleculen. In figuur 2 zijn de structuurformules van twee PCB's weergegeven. Een molecuul PCB-126 kan ook een platte vorm aannemen, wat mede verklaart waarom deze stof een vergelijkbare toxische werking heeft als 2,3,7,8-tetrachloor-DD. PCB-54 heeft deze toxische werking niet. figuur 2: structuurformule van PCB-126 (chlooratomen op vijf posities, niet op de ortho-posities naast de centrale C–C-binding tussen de ringen) en structuurformule van PCB-54 (chlooratomen op de vier ortho-posities naast de centrale C–C-binding, waterstofatomen op de overige posities).$$, 'inline'),
  ('2599d77d-1047-4094-a02c-efcf23d467ca', 'cfa09c3b-6226-4b04-bd3d-c31f84d1ae7b', $$figuur 3 — massaspectrum 2,3,7,8-tetrachloor-DD (molecuulion-formule)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-dioxines-en-pcbs-context3.png$$,
   $$Dioxines ontstaan bij verbrandingsreacties, zowel in verbrandingsovens als bij natuurlijke branden. Eenmaal in het milieu terechtgekomen, hopen dioxines zich op in het vetweefsel van onder andere paling. Omdat paling wordt geconsumeerd, wordt regelmatig onderzocht of in paling dioxines aanwezig zijn. Hiertoe worden monsters van palingen genomen, waarna met massaspectrometrie wordt bepaald welke stoffen in de monsters aanwezig zijn. figuur 3: massaspectrum van zuiver 2,3,7,8-tetrachloor-DD (vereenvoudigd), intensiteit (%) tegen m/z. Drie samenhangende piekenbundels: vanaf m/z = 320 vijf pieken (320, 322, 324, 326, 328, hoogste piek bij 322), vanaf m/z = 257 vier pieken (257, 259, 261, 262, hoogste piek bij 259), vanaf m/z = 194 drie pieken (194, 196, 198). De bundel van vijf pieken vanaf m/z = 320 is afkomstig van het molecuulion. De formule van het molecuulion is C₁₂H₄O₂Cl₄⁺.$$, 'inline'),
  ('e4e83bb1-c1d8-4507-b310-290e457881bf', 'cfa09c3b-6226-4b04-bd3d-c31f84d1ae7b', $$piekenbundels-toelichting (COCl-afsplitsing)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-dioxines-en-pcbs-context4.png$$,
   $$In het massaspectrum zijn drie samenhangende piekenbundels te zien. Vanaf m/z = 320 zijn er vijf pieken van het molecuulion, vanaf m/z = 257 vier pieken van één fragmention en vanaf m/z = 194 drie pieken van één volgend fragmention. De piekenbundels ontstaan doordat telkens een fragment COCl afsplitst.$$, 'inline'),
  ('b176f488-2c6c-4691-ba94-33336c48ef70', 'f2c77b4b-45d0-46c4-99dc-8c4cc4db34f3', $$figuur 1 — elektrochemische cel CO2 naar methanol (polyaniline-elektrode)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-alcoholen-uit-co2-context1.png$$,
   $$figuur 1: elektrochemische cel voor de omzetting van CO₂ tot methanol. De cel bevat een polyaniline-elektrode; hierop wordt CO₂ + H⁺ omgezet tot CH₃OH en H₂O.$$, 'inline'),
  ('13054d7f-8cc8-4eef-a94b-7ca494813b38', 'f2c77b4b-45d0-46c4-99dc-8c4cc4db34f3', $$totaalvergelijking CO2 naar methanol en O2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-alcoholen-uit-co2-context2.png$$,
   $$De totaalvergelijking van de reactie in de elektrochemische cel is hieronder weergegeven. totaalreactie: 2 CO₂ (g) + 4 H₂O (l) → 2 CH₃OH (l) + 3 O₂ (g)$$, 'inline'),
  ('5930713b-9eed-44c6-9e15-ac02682c4fd9', 'f2c77b4b-45d0-46c4-99dc-8c4cc4db34f3', $$elektrode-experiment inleiding (polyaniline, licht/donker, CO2 blanco/verzadigd)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-alcoholen-uit-co2-context3.png$$,
   $$De elektrode die in het onderzoek is gebruikt, was bedekt met een laagje polyaniline. Hiervoor is gekozen omdat door de polyaniline niet alleen elektrische energie maar ook lichtenergie kan worden overgedragen bij elektrochemische reacties. Het rendement van de omzetting van CO₂ tot methanol nam inderdaad sterk toe wanneer de elektrode werd belicht met een felle lamp. Men heeft de stroomsterkte tijdens de omzetting onderzocht, waarbij de volgende omstandigheden werden gekozen: − De oplossing bevatte geen CO₂ (blanco) of was juist verzadigd met CO₂. − De cel werd verlicht of verduisterd.$$, 'inline'),
  ('bdc855b0-bb49-4ff3-b29d-57229bac3f6a', 'f2c77b4b-45d0-46c4-99dc-8c4cc4db34f3', $$tabel — stroomsterktes bij pH 4/7, licht/donker, met/zonder CO2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-alcoholen-uit-co2-context4.png$$,
   $$Voorafgaand aan de experimenten werd met een buffer de waarde van de pH ingesteld op 4 ofwel op 7. De resultaten van de metingen zijn in de tabel weergegeven. De waardes in de tabel zijn de gemeten stroomsterktes in µA. tabel: blanco (donker/licht) en verzadigd met CO₂ (donker/licht) — pH = 4: 7 / 34 / 12 / 67; pH = 7: 2 / 6 / 8 / 15.$$, 'inline'),
  ('e19ebcbd-8e7b-464f-8ecb-d3bf4d17a53f', 'f2c77b4b-45d0-46c4-99dc-8c4cc4db34f3', $$conclusies 1 en 2 — halfreactie 2H+ + 2e- naar H2 aan polyaniline-elektrode$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-alcoholen-uit-co2-context5.png$$,
   $$Uit de blanco metingen blijkt dat er ook stroom loopt als er geen CO₂ aanwezig is. De stoffen uit de gebruikte buffer kunnen niet als oxidator optreden, en verklaren dus ook niet de stroom die er loopt. Op grond van de resultaten formuleerden de onderzoekers twee conclusies: 1 Aan de polyaniline elektrode verloopt ook de halfreactie 2 H⁺ + 2 e⁻ → H₂. 2 De halfreactie 2 H⁺ + 2 e⁻ → H₂ wordt ook versneld door de polyaniline elektrode.$$, 'inline'),
  ('ec08ba5d-99fe-4b6b-9066-30334f3134ae', 'f2c77b4b-45d0-46c4-99dc-8c4cc4db34f3', $$figuur 2 — chromatogrammen standaardoplossing en monster (GC methanol/ethanol)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-alcoholen-uit-co2-context6.png$$,
   $$Uit onderzoek met gaschromatografie bleek dat er behalve methanol ook een aanzienlijke hoeveelheid ethanol aan de polyaniline elektrode wordt gevormd. In het onderzoek werd de ontstane molverhouding tussen ethanol en methanol bepaald. Aangezien de detector een verschillende gevoeligheid kent voor ethanol en methanol werd eerst een chromatogram gemaakt met een standaardoplossing. Deze standaardoplossing bevatte ethanol en methanol in de molverhouding 1 : 1. figuur 2: chromatogram van de standaardoplossing (piek methanol 112,7; piek ethanol 105,5) en van een monster (piek methanol 69,1; piek ethanol 43,6), signaal tegen retentietijd; methanol elueert vóór ethanol in beide chromatogrammen.$$, 'inline'),
  ('408421f9-f8ea-4900-b800-8daea5196f7d', '94324e6a-0d71-4977-9205-8ce3dec7e60a', $$tabel 1 — vetzuren en afkortingen (L,O,P,S) + triglyceride SOS$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-biodiesel-uit-sheaboter-context1.png$$,
   $$tabel 1: vetzuur en afkorting — linolzuur: L; oliezuur: O; palmitinezuur: P; stearinezuur: S. Onderzocht wordt of sheaboter ook geschikt is als grondstof voor biodiesel. Biodiesel wordt verkregen door de reactie van methanol met de triglyceriden. In deze reactie worden de vetzuren volledig omgezet tot methylesters. Het meest voorkomende triglyceride in sheaboter wordt aangeduid met de afkorting SOS.$$, 'inline'),
  ('412f2ab8-666d-4136-bc84-01b44e741141', '94324e6a-0d71-4977-9205-8ce3dec7e60a', $$tabel 2 — samenstelling monster sheaboter (SOS,SOO,OOO,SLO)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-biodiesel-uit-sheaboter-context2.png$$,
   $$Behalve SOS komen nog andere triglyceriden in sheaboter voor. tabel 2: samenstelling van een monster sheaboter — triglyceride, massapercentage (%), molaire massa (g mol⁻¹): SOS 41,0 / 889; SOO 37,5 / 887; OOO 11,0 / 885; SLO 10,5 / 885.$$, 'inline'),
  ('4de43825-cea8-4780-94d4-df53194897f7', '94324e6a-0d71-4977-9205-8ce3dec7e60a', $$verbranding biodiesel — 10% naar CO, rest naar CO2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-biodiesel-uit-sheaboter-context3.png$$,
   $$In een proefopstelling werd een monster van de gevormde biodiesel verbrand. Het bleek dat onder de gebruikte omstandigheden 10% van de koolstofatomen werd omgezet tot koolstofmono-oxide en de rest tot koolstofdioxide.$$, 'inline'),
  ('e31d20b2-8933-474c-a89d-f91b592395f6', '668b73ae-5afe-4e53-9dcf-502711507473', $$figuur 1 — vorming van PHA via HA-S-CoA (stap 1 en stap 2)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-bacteriele-polymeren-context1.png$$,
   $$figuur 1: vorming van PHA. Stap 1: x HO-CH(R)-CH₂-C(=O)-OH (HA) + x H-S-CoA → x HO-CH(R)-CH₂-C(=O)-S-CoA (HA-S-CoA) + x H₂O. Stap 2 (onder invloed van het enzym PHA-synthase): HO-CH(R)-CH₂-C(=O)-OH (HA) + HA-S-CoA-eenheden → H-[O-CH(R)-CH₂-C(=O)]ₓ₊₁-OH (PHA) + x H-S-CoA.$$, 'inline'),
  ('b067b226-d910-49e3-9c36-440455598df2', '668b73ae-5afe-4e53-9dcf-502711507473', $$systematische naamgeving PHA-polymeren (poly- + monomeernaam)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-bacteriele-polymeren-context2.png$$,
   $$In de structuur van een molecuul van een HA kan onder andere de groep R variëren. Hierdoor kunnen vele soorten PHA worden gevormd. De systematische naam van een polyester zoals PHA wordt gevormd door 'poly-' gevolgd door de systematische naam van het monomeer.$$, 'inline'),
  ('00a27580-957b-44a0-a63f-05594bb9b09c', '668b73ae-5afe-4e53-9dcf-502711507473', $$oriëntatie HA-S-CoA in enzym — interactie met ~Cys-$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-bacteriele-polymeren-context3.png$$,
   $$Bij de vorming van PHA door PHA-syntase wordt telkens een nieuwe eenheid HA gekoppeld aan het zich vormende polymeer. Het blijkt dat hierbij een molecuul HA-S-CoA op een specifieke manier georiënteerd is in het enzym. Dit is op de uitwerkbijlage bij vraag 16 weergegeven. Deze oriëntatie wordt onder andere mogelijk doordat een atoomgroep van het HA-S-CoA een elektrostatische interactie heeft met de negatief geladen restgroep van een cysteïne-eenheid ~Cys⁻ in de peptideketen van PHA-synthase.$$, 'inline'),
  ('4ed63a8e-9a7b-4fe4-b17f-f7b1170357cf', '668b73ae-5afe-4e53-9dcf-502711507473', $$nucleofiele aanval ~Cys- op HA-S-CoA (mechanisme-inleiding)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-bacteriele-polymeren-context4.png$$,
   $$De weergegeven oriëntatie is voorwaarde voor de nucleofiele aanval van ~Cys⁻ op het molecuul HA-S-CoA. Hierbij wordt een eenheid HA gekoppeld aan de eiwitketen en komt een deeltje [S-CoA]⁻ vrij.$$, 'inline'),
  ('83337d8f-917d-4f3b-bb6a-de1d3312d9be', '668b73ae-5afe-4e53-9dcf-502711507473', $$copolymeren — experiment 1 (tegelijk) vs experiment 2 (afwisselend)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-bacteriele-polymeren-context5.png$$,
   $$De bacteriën zetten voedingsstoffen via meerdere routes om in HA-S-CoA. Bij sommige routes blijven (delen van) de moleculen van de voedingsstof intact. Daardoor is het mogelijk om de R-groep in het PHA te wijzigen door de voeding van de bacteriën te wijzigen. Een onderzoeksgroep is erin geslaagd om de bacteriën copolymeren te laten maken. Het bleek mogelijk om zowel willekeurige (random)-copolymeren als blok-copolymeren te verkrijgen. Om dit voor elkaar te krijgen, gaf men twee soorten voeding aan de bacteriën. In experiment 1 werden de twee voedingsstoffen tegelijkertijd aangeboden, in experiment 2 werden de twee voedingsstoffen afwisselend aangeboden.$$, 'inline'),
  ('1e5ef616-88ad-4ef6-b79e-e3820fc5a49c', '668b73ae-5afe-4e53-9dcf-502711507473', $$trekproef-methode + figuur 2 — aangelegde kracht vs verlenging (R=C3H7, R=C5H11)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-bacteriele-polymeren-context6.png$$,
   $$Deze stroken zijn vervolgens onderworpen aan een trekproef. Hierbij wordt gemeten hoeveel langer een strook PHA wordt afhankelijk van de aangelegde kracht. figuur 2: meetresultaten van twee soorten PHA met verschillende R-groepen (aangelegde kracht tegen verlenging in %, 0-200%); R = C₃H₇ (stippellijn) ligt over het hele traject boven R = C₅H₁₁ (doorgetrokken lijn), beide vlakken af naar een plateau.$$, 'inline'),
  ('c0c8ffee-c732-455e-a764-a9ac02493f3d', '668b73ae-5afe-4e53-9dcf-502711507473', $$uitwerkbijlage vraag 16 — mechanisme HA-S-CoA + ~Cys- (Phe, Cys- omkaderd)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-bacteriele-polymeren-context7.png$$,
   $$uitwerkbijlage bij vraag 16: onvolledig reactiemechanisme. Links de peptideketen met twee omkaderde (leeg te tekenen) delen voor de aminozuureenheden Phe en Cys⁻ (Cys⁻ met zijgroep S⁻); rechts daarvan het molecuul HA-S-CoA, weergegeven als CoA-S-C(=O)-CH₂-CH(R)-O-H, met het waterstofatoom van de OH-groep dicht bij de S⁻ van Cys⁻. Onder de peptideketen de groeiende PHA-keten. De kandidaat moet de ontbrekende delen van Phe en Cys⁻ tekenen, de niet-bindende elektronenparen bij de reeds getekende atomen toevoegen en met pijlen de verplaatsing van elektronenparen tijdens de nucleofiele aanval weergeven.$$, 'uitwerkbijlage'),
  ('489a2710-1fa3-41a8-9a45-0168af84aa24', '1f6b7a77-3520-4ed2-a31c-f28fd34ab064', $$figuur — concentraties 5 stoffen (methanol, butaan-2-on, koolstofdisulfide, pentaan-2-on, limoneen) bij patiënten vs controle$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-ademtest-voor-leverziekte-context1.png$$,
   $$figuur: gehalte (nmol per mol lucht) van vijf stoffen (methanol, butaan-2-on, koolstofdisulfide, pentaan-2-on, limoneen) in uitgeademde lucht van de patiëntengroep (P) en de controlegroep (C), met gemiddelde waarde (punt) en spreiding van de meetwaarden (balk). Bij methanol, butaan-2-on en koolstofdisulfide overlappen de spreidingsbalken van P en C sterk; bij pentaan-2-on is er een kleinere overlap; bij limoneen is er geen overlap tussen de spreiding van P (hoger, met grote spreiding) en C (laag, met kleine spreiding).$$, 'inline'),
  ('0576e311-394b-40bb-9b0d-1fbfbb0575e3', '1f6b7a77-3520-4ed2-a31c-f28fd34ab064', $$proton transfer massaspectrometrie — ionisatiereactie H3O+ + R, protonering pentaan-2-on$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-ademtest-voor-leverziekte-context2.png$$,
   $$Bij de metingen werd onder andere gebruikgemaakt van 'proton transfer massaspectrometrie'. Bij deze techniek treedt de ionisatie in de gasfase op door botsingen van H₃O⁺-ionen met moleculen R van vluchtige organische verbindingen. De ionisatie kan als volgt worden voorgesteld: H₃O⁺ (g) + R (g) → H₂O (g) + RH⁺ (g). Als in een molecuul R een zuurstofatoom voorkomt, bindt in deze reactie het waterstofion aan het zuurstofatoom. Wanneer pentaan-2-on een waterstofion bindt, is mesomerie mogelijk in het gevormde molecuulion. Bij een van de grensstructuren van [pentaan-2-on–H]⁺ voldoet een atoom niet aan de octetregel.$$, 'inline'),
  ('703cbf43-9ccf-4a77-be67-61a750e72e3e', '1f6b7a77-3520-4ed2-a31c-f28fd34ab064', $$geprotoneerd limoneen — fragmentatiepieken m/z=67,81,95$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-ademtest-voor-leverziekte-context3.png$$,
   $$Bij geprotoneerd limoneen (C₁₀H₁₇⁺, m/z = 137) treden fragmentaties op, waarbij telkens een neutraal deeltje en een geladen deeltje worden gevormd. De geladen fragmenten die ontstaan, geven respectievelijk pieken bij m/z = 67 en m/z = 81 en m/z = 95. De neutrale fragmenten die hierbij worden afgesplitst, behoren tot een klasse van koolwaterstoffen.$$, 'inline'),
  ('27c0dcb2-25ee-454b-8677-90a929bf0854', '1f6b7a77-3520-4ed2-a31c-f28fd34ab064', $$verdeling limoneen — evenwichten vet/bloed/lucht (K1, K2)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-ademtest-voor-leverziekte-context4.png$$,
   $$Limoneen is aanwezig in vetweefsel, in bloed en in de adem. De onderzoekers wilden op basis van de gemeten concentratie limoneen in de adem een schatting maken van de hoeveelheid limoneen die is opgehoopt in het vet van een leverpatiënt. Hiertoe hebben ze experimenten uitgevoerd waarin de verdeling van limoneen tussen olijfolie en bloed en tussen bloed en lucht is bepaald. Ze namen hierbij aan dat olijfolie en vetweefsel vergelijkbare oplosmiddelen zijn voor limoneen. De verdeling van limoneen over deze drie fases is hieronder voorgesteld met twee evenwichten. limoneen (vet) ⇌ limoneen (bloed), K₁ = 7,1·10⁻³. limoneen (bloed) ⇌ limoneen (lucht), K₂ = 2,8·10⁻². De concentratie limoneen wordt bij de berekening van K uitgedrukt in mol L⁻¹. Bij een patiënt bedroeg de concentratie limoneen in de uitgeademde lucht 0,10 volume-ppm. Aan de hand van bovenstaande gegevens en aannames kan worden berekend dat de concentratie limoneen in het vetweefsel van deze patiënt 2,1·10⁻⁵ mol L⁻¹ bedraagt.$$, 'inline'),
  ('c70abb9a-6a9e-40bf-b63c-7e97ecfbf972', '1f6b7a77-3520-4ed2-a31c-f28fd34ab064', $$patiëntgegevens — massa, vetpercentage, dichtheid lichaamsvet$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-iii-ademtest-voor-leverziekte-context5.png$$,
   $$De patiënt had een massa van 85 kg en een vetpercentage van 35 massa%. De gemiddelde dichtheid van lichaamsvet is 0,90 kg L⁻¹.$$, 'inline');

